## Problem1(A.6.6.60)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "niceTables.pl",
  "contextCurrency.pl",
  "contextForm.pl",
  "parserPopUp.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$b = random(250, 400, 10);
$r = random(100, 200, 5);
$n = random(4, 8);
Context("Currency")->flags->set(trimTrailingZeros => 1);
$base = Currency($b);
$rate = Currency($r);
$total = Currency($b + $r*$n);
Context()->variables->are(n => 'Real');
$proposed_solution = (random(0,1)) ? $n : $n + non_zero_random(-1, 3);
$left = Formula("$b + $r n");
$right = Formula($total->value);
Context("LimitedNumeric");
$lefteval = Real($left->eval(n => $proposed_solution));
$righteval = Real($right->eval(n => $proposed_solution));
$dropdown = DropDown(
  ["Yes, it is a solution.", "No, it is not a solution."],
  ($lefteval == $righteval) ? 0 : 1, showInStatic => 0
);

############################################################
# Body
############################################################

BEGIN_PGML
The rental fee for a beach house is [`[$base]`] plus [`[$rate]`] per night. If you stay [`n`] nights, the total is [`[$left]\text{.}`] You stayed and the total was [`[$total]\text{,}`] giving the equation [`[$left]=[$right]\text{.}`] Did you stay [`[$proposed_solution]`] nights?

>> [@DataTable(
  [
    [PGML('[`[$left->TeX]`]'),
     PGML('[`=`]'),
     PGML('[`[$right->TeX]`]'),
    ],
    [PGML('[_]{$lefteval}{3}'),
     PGML('[`\wonder{=}`]'),
     PGML('[`[$righteval->TeX]`]'),
    ],
  ],
      align => 'rcl',
      valign => 'middle',);@]* <<

[_]{$dropdown}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
